@@ -19822,22 +19822,59 @@ public:
             cast<Instruction>(ReductionOps.front().front())->getDebugLoc());
         if (AnyBoolLogicOp) {

-          if (auto It = ReducedValsToOps.find(VectorizedTree);
-              It == ReducedValsToOps.end() ||
-              isGuaranteedNotToBePoison(VectorizedTree, AC) ||
-              any_of(It->getSecond(), [&](Instruction *I) {
-                return isBoolLogicOp(I) &&
-                       getRdxOperand(I, 0) == VectorizedTree;
-              })) {
-            ;
-          } else if (auto It = ReducedValsToOps.find(Res);
-                     It == ReducedValsToOps.end() ||
-                     isGuaranteedNotToBePoison(Res, AC) ||
-                     any_of(It->getSecond(), [&](Instruction *I) {
-                       return isBoolLogicOp(I) && getRdxOperand(I, 0) == Res;
-                     })) {
+          // For boolean logic reductions, we must be careful not to use a
+          // potentially poison value as the select condition. Consider a value
+          // safe if it is provably non-poison or it originally appeared as the
+          // select condition in a boolean logic op.
+          auto IsSafeAsCond = [&](Value *V) {
+            if (isGuaranteedNotToBePoison(V, AC))
+              return true;
+            // Results of vector.reduce.{and,or} are considered safe in the
+            // context of SLP boolean reductions because the vector inputs are
+            // frozen earlier (see freezing of VectorizedRoot), which prevents
+            // poison propagation.
+            if (auto *CI = dyn_cast<CallInst>(V))
+              if (Function *F = CI->getCalledFunction())
+                if (F->isIntrinsic()) {
+                  Intrinsic::ID ID = F->getIntrinsicID();
+                  if (ID == Intrinsic::vector_reduce_and ||
+                      ID == Intrinsic::vector_reduce_or)
+                    return true;
+                }
+            auto It = ReducedValsToOps.find(V);
+            if (It == ReducedValsToOps.end())
+              return false;
+            return any_of(It->getSecond(), [&](Instruction *I) {
+              return isBoolLogicOp(I) && getRdxOperand(I, 0) == V;
+            });
+          };
+          auto IsCondCandidate = [&](Value *V) {
+            auto It = ReducedValsToOps.find(V);
+            if (It == ReducedValsToOps.end())
+              return false;
+            return any_of(It->getSecond(), [&](Instruction *I) {
+              return isBoolLogicOp(I) && getRdxOperand(I, 0) == V;
+            });
+          };
+          bool VTSafe = IsSafeAsCond(VectorizedTree);
+          bool ResSafe = IsSafeAsCond(Res);
+          bool VTCand = IsCondCandidate(VectorizedTree);
+          bool ResCand = IsCondCandidate(Res);
+          if ((!VTSafe && ResSafe) || (!VTCand && ResCand)) {
             std::swap(VectorizedTree, Res);
-          } else {
+          } else if (!VTSafe && !ResSafe) {
+            // Neither operand is known-safe as a condition. Prefer to use as
+            // the condition a value that participates more in the original
+            // boolean reduction (has more associated ops). This heuristic keeps
+            // the resulting IR closer to the original patterns and matches
+            // existing expectations. Then freeze the chosen condition to avoid
+            // poison from leaking due to reassociation.
+            auto NumOps = [&](Value *V) {
+              auto It = ReducedValsToOps.find(V);
+              return It == ReducedValsToOps.end() ? 0u : (unsigned)It->second.size();
+            };
+            if (NumOps(Res) > NumOps(VectorizedTree))
+              std::swap(VectorizedTree, Res);
             VectorizedTree = Builder.CreateFreeze(VectorizedTree);
           }
         }
@@ -19931,6 +19968,7 @@ public:
         }
       }

+
       // Emit code for constant values.
       if (Candidates.size() > 1 && allConstant(Candidates)) {
