@@ -20346,6 +20384,22 @@ public:
                                                    bool InitStep) {
         if (!AnyBoolLogicOp)
           return;
+        auto IsCondCandidateV = [&](Value *V) {
+          auto It = ReducedValsToOps.find(V);
