+            return isBoolLogicOp(I) && getRdxOperand(I, 0) == V;
+          });
+        };
+        // On the initial combine, if the current condition is the vectorized
+        // reduction tree and the other operand is known to have served as a
+        // boolean select condition in the original code, prefer using that
+        // scalar gating value as the condition.
+        if (InitStep && LHS == VectorizedTree && IsCondCandidateV(RHS)) {
